# Hybrid evaluator: deterministic checks first, LLM judge only for
# criteria that can't be verified programmatically.

import re

def deterministic_checks(output: str, criteria: list[str]) -> dict[str, bool]:
    """Run cheap structural checks. Return {criterion: pass/fail}."""
    results: dict[str, bool] = {}
    for c in criteria:
        cl = c.lower()
        if 'json' in cl:
            try:
                import json as _j; _j.loads(output)
                results[c] = True
            except Exception:
                results[c] = False
        elif 'bullet' in cl:
            n = int(re.search(r'(\d+)', c).group(1)) if re.search(r'(\d+)', c) else 0
            bullets = [l for l in output.splitlines() if l.strip().startswith(('-', '*', '•'))]
            results[c] = len(bullets) == n
        else:
            results[c] = None  # needs LLM evaluation
    return results

def hybrid_evaluate(
    client,
    goal: str,
    criteria: list[str],
    output: str,
    threshold: float = 0.8,
) -> EvalResult:
    structural = deterministic_checks(output, criteria)
    llm_criteria = [c for c, v in structural.items() if v is None]
    llm_result = None
    if llm_criteria:
        llm_result = evaluate_output(client, goal, llm_criteria, output, threshold)
    # Combine
    n = len(criteria)
    passed_count = sum(1 for v in structural.values() if v is True)
    llm_score = llm_result.score if llm_result else 1.0
    structural_score = passed_count / max(n, 1)
    overall = (structural_score + llm_score) / 2
    feedback_parts = [
        f'{c}: FAILED' for c, v in structural.items() if v is False
    ]
    if llm_result and llm_result.feedback:
        feedback_parts.append(llm_result.feedback)
    return EvalResult(
        score=overall,
        passed=overall >= threshold,
        feedback='\n'.join(feedback_parts),
    )
